#include <stdio.h>
#include <stdlib.h>

int gcd(int a, int b) {
    while (b != 0) {
        int temp = b;
        b = a % b;
        a = temp;
    }
    return a;
}

int main() {
    int n;
    scanf("%d", &n);

    int *pre = (int *)malloc(n * sizeof(int));
    int *suf = (int *)malloc(n * sizeof(int));
    int *v1 = (int *)malloc(n * sizeof(int));

    for (int i = 0; i < n; i++) {
        scanf("%d", &v1[i]);
        if (i == 0) {
            pre[i] = v1[i];
        } else {
            pre[i] = gcd(v1[i], pre[i - 1]);
        }
    }

    for (int i = n - 1; i >= 0; i--) {
        if (i == n - 1) {
            suf[i] = v1[i];
        } else {
            suf[i] = gcd(v1[i], suf[i + 1]);
        }
    }

    int fans = 0;
    for (int i = 0; i < n; i++) {
        if (i == 0) {
            fans = (fans > suf[i + 1]) ? fans : suf[i + 1];
        } else if (i == n - 1) {
            fans = (fans > pre[i - 1]) ? fans : pre[i - 1];
        } else {
            int current_gcd = gcd(pre[i - 1], suf[i + 1]);
            fans = (fans > current_gcd) ? fans : current_gcd;
        }
    }

    printf("%d\n", fans);

    free(pre);
    free(suf);
    free(v1);

    return 0;
}

